import React from 'react';
import { useState } from 'react';
import { Formik, Field, Form } from 'formik';

function ConfirmationForm() {
  const [submittedValues, setSubmittedValues] = useState(null);

  const initialValues = {
    name: '',
    email: '',
  };

  const validate = (values) => {
    const errors = {};
    if (!values.name) {
      errors.name = 'Name is required';
    }
    if (!values.email) {
      errors.email = 'Email is required';
    } else if (!values.email.includes('@')) {
      errors.email = 'Enter a valid email address';
    }
    return errors;
  };

  const handleSubmit = (values, formikHelpers) => {
    setSubmittedValues(values);
    formikHelpers.setSubmitting(false);
  };

  return (
    <div className="container mt-5">
      <h1>Workshop Signup</h1>
      <Formik initialValues={initialValues} validate={validate} onSubmit={handleSubmit}>
        {(formik) => (
          <Form data-testid="confirmation-form">
            <div className="mb-3">
              <label htmlFor="name" className="form-label">Full Name</label>
              <Field type="text" className="form-control" id="name" name="name" />
              {formik.touched.name && formik.errors.name && (
                <div data-testid="name-error" className="text-danger">
                  {formik.errors.name}
                </div>
              )}
            </div>

            <div className="mb-3">
              <label htmlFor="email" className="form-label">Email</label>
              <Field type="email" className="form-control" id="email" name="email" />
              {formik.touched.email && formik.errors.email && (
                <div data-testid="email-error" className="text-danger">
                  {formik.errors.email}
                </div>
              )}
            </div>

            <button
              type="submit"
              className="btn btn-primary"
              data-testid="submit"
              disabled={formik.isSubmitting}
            >
              Confirm Signup
            </button>
          </Form>
        )}
      </Formik>
      <pre data-testid="submitted-values">
        {submittedValues ? JSON.stringify(submittedValues) : ''}
      </pre>
    </div>
  );
}

export default ConfirmationForm;

